INSERT INTO `wp_term_taxonomy` (`term_taxonomy_id`, `term_id`, `taxonomy`, `description`, `parent`, `count`) VALUES
(1, 1, 'category', '', 0, 1),
(2, 2, 'lyly_room_cat', 'Superior Room là sự lựa chọn hoàn hảo cho những khách hàng tìm kiếm sự cân bằng giữa tiện nghi hiện đại và không gian ấm cúng. Với thiết kế tinh tế, tối giản nhưng không kém phần sang trọng, mỗi phòng Superior đều mang lại cảm giác thư giãn tuyệt đối ngay từ khi bước chân vào.\r\n\r\nĐặc điểm nổi bật:\r\n\r\n★ Không gian nội thất: Phòng được lát sàn gỗ cao cấp hoặc gạch vân đá sang trọng, kết hợp hài hòa với nội thất gỗ tự nhiên từ giường ngủ, bàn trang điểm đến tủ quần áo.\r\n\r\n★ Ánh sáng tự nhiên: Hệ thống cửa sổ lớn hoặc ban công rộng với rèm cửa hai lớp giúp bạn dễ dàng điều chỉnh ánh sáng và tận hưởng tầm nhìn ra không gian xanh mát bên ngoài.\r\n\r\n★ Tiện nghi cao cấp:\r\n\r\n     ⚝ Giường đôi cỡ lớn với bộ chăn ga gối đệm trắng tinh khôi, êm ái.\r\n\r\n     ⚝ Khu vực tiếp khách nhỏ gọn với ghế sofa hoặc ghế bành thư giãn.\r\n\r\n     ⚝ Trang thiết bị hiện đại: TV màn hình phẳng, điều hòa không khí âm trần, điện thoại bàn và bộ dụng cụ pha trà/cà phê tiện lợi.\r\n\r\n★ Trang trí: Không gian thêm phần nghệ thuật với các bức tranh treo tường chủ đề phong cảnh và con người, tạo điểm nhấn nhẹ nhàng cho căn phòng.', 0, 4),
(3, 3, 'lyly_branch', '', 0, 14),
(4, 4, 'lyly_branch', '', 0, 5),
(5, 5, 'lyly_room_cat', 'Deluxe Room là hạng phòng mang đến trải nghiệm nghỉ dưỡng nâng tầm với không gian rộng rãi, thiết kế sang trọng và tràn ngập ánh sáng tự nhiên. Đây là sự lựa chọn lý tưởng cho những ai muốn tận hưởng sự riêng tư tuyệt đối trong một không gian tinh tế và đẳng cấp.\r\n\r\nĐiểm nhấn nổi bật:\r\n\r\n★ Thiết kế &amp; Không gian: Căn phòng sử dụng tông màu trắng thanh lịch kết hợp cùng nội thất gỗ ấm áp. Sàn nhà được lát gạch vân đá cao cấp, tạo cảm giác mát mẻ và sạch sẽ.\r\n\r\n★ View &amp; Ánh sáng: Hệ thống cửa kính lớn từ sàn đến trần dẫn lối ra ban công riêng biệt. Tại đây, bạn có thể thư giãn và ngắm nhìn cảnh quan thành phố hoặc khuôn viên xanh mát của khách sạn.\r\n\r\n★ Tiện nghi nghỉ ngơi:\r\n\r\n     ⚝ Giường King-size êm ái với bộ ga gối cao cấp, đảm bảo giấc ngủ sâu.\r\n\r\n     ⚝ Khu vực thư giãn ngay tại phòng với ghế sofa hiện đại và bàn trà nhỏ.\r\n\r\n★ Trang bị đầy đủ: Phòng được tích hợp đầy đủ tiện nghi hiện đại bao gồm điều hòa âm trần, TV màn hình lớn, bàn làm việc/trang điểm và các vật dụng trang trí tinh tế như tranh nghệ thuật, cây xanh trong nhà.', 0, 3),
(6, 6, 'lyly_room_cat', 'VIP Room là hạng phòng cao cấp nhất, mang đến không gian nghỉ dưỡng thượng lưu, rộng rãi và biệt lập. Được thiết kế chú trọng vào sự sang trọng và tiện nghi vượt trội, đây là lựa chọn hoàn hảo cho những chuyến công tác, kỳ nghỉ trăng mật hoặc những khách hàng muốn tự thưởng cho mình một trải nghiệm lưu trú đẳng cấp nhất.\r\n\r\nNhững đặc quyền và điểm nhấn nổi bật:\r\n★ Không gian đẳng cấp &amp; Tầm nhìn panorama: Phòng sở hữu diện tích lớn với hệ thống cửa vòm kính kéo dài từ trần xuống sàn, mở ra một ban công rộng rãi. Tại đây được trang bị sẵn bộ bàn ghế ngoài trời để bạn có thể thư thái nhâm nhi cà phê và ngắm nhìn toàn cảnh thành phố thơ mộng.\r\n★ Nội thất thượng hạng: Sàn đá marble vân mây sang trọng kết hợp hài hòa với nội thất gỗ tự nhiên cao cấp. Giường ngủ King-size được bố trí ở trung tâm phòng với bộ chăn ga gối đệm êm ái, mang lại giấc ngủ hoàng gia.\r\n★ Khu vực tiếp khách riêng biệt: Ngay trong phòng được bố trí một băng ghế sofa da dáng cong hiện đại màu cam ấm cùng bàn trà tinh tế, tạo không gian lịch sự để tiếp khách hoặc thư giãn xem TV.\r\n★ Tiện nghi VIP đầy đủ: * Hệ thống điều hòa âm trần hiện đại.\r\n     ⚝ Smart TV màn hình lớn, tủ lạnh mini tích hợp gọn gàng trong tủ gỗ.\r\n     ⚝ Bàn trang điểm/bàn làm việc riêng, tủ quần áo lớn, bình đun nước siêu tốc và bộ tách trà sứ cao cấp.\r\n★ Nghệ thuật bài trí: Căn phòng thêm phần sinh động và thư thái nhờ các bức tranh phong cảnh thiên nhiên rực rỡ cùng các chậu cây xanh phong thủy thanh lọc không khí như cây Lưỡi Hổ.\r\n', 0, 3),
(8, 8, 'lyly_room_cat', 'Deluxe Twin mang đến một không gian nghỉ dưỡng nâng tầm, rộng rãi và tràn ngập sự thư thái cho các cặp đôi, gia đình hoặc nhóm bạn. So với hạng phòng tiêu chuẩn, Deluxe Twin sở hữu những nét chấm phá tinh tế trong thiết kế nội thất cùng không gian phòng tắm được đầu tư chuẩn thượng lưu, hứa hẹn mang lại những giây phút nghỉ ngơi trọn vẹn nhất.\r\n\r\nNhững điểm nhấn nổi bật của hạng phòng:\r\n\r\n★ Hệ thống giường đôi linh hoạt: Phòng được trang bị 2 giường đơn cỡ lớn biệt lập với đệm lò xo cao cấp, gối ôm và bộ chăn ga trắng muốt, đảm bảo sự riêng tư và mang lại giấc ngủ sâu cho từng khách lưu trú.\r\n\r\n★ Không gian tinh tế &amp; Ấm cúng: Sàn phòng được linh hoạt lát gỗ cao cấp hoặc gạch vân đá sang trọng. Ánh sáng tự nhiên được tối ưu qua khung cửa sổ lớn đi kèm rèm sáo gỗ/rèm cuốn hiện đại, giúp bạn dễ dàng điều chỉnh không gian theo ý muốn.\r\n\r\n★ Góc thư giãn dễ thương: Phòng bố trí một góc nhỏ với bộ bàn trà sứ cùng cặp ghế nệm đơn dáng ôm (tông màu pastel nhẹ nhàng như hồng hoặc kem), kết hợp với các bức tranh sơn dầu đồng quê, tranh thiếu nữ tạo cảm giác vô cùng ấm cúng.\r\n\r\n★ Trang thiết bị hiện đại:\r\n\r\n     ⚝ Hệ thống điều hòa âm trần làm mát nhanh và êm ái.\r\n\r\n     ⚝ Tủ quần áo gỗ tự nhiên đa năng, tích hợp tủ lạnh mini (minibar), bình đun nước siêu tốc và máy sấy tóc tiện lợi.\r\n\r\n     ⚝ Bàn trang điểm kết hợp gương tròn viền gỗ thanh lịch.\r\n\r\n★ Phòng tắm VIP - Trải nghiệm thư giãn tuyệt đối: Điểm đắt giá nhất của hạng phòng Deluxe Twin chính là phòng tắm siêu rộng, được lát gạch giả gỗ hoặc đá marble vân vàng sang trọng. Tại đây, khách hàng có thể thả mình trong bồn tắm nằm góc cỡ lớn, ngắm nhìn bức tranh mosaic chủ đề đại dương/thiên nhiên rực rỡ và tận hưởng làn nước mát từ vòi sen cây hiện đại.', 0, 2),
(7, 7, 'lyly_room_cat', 'Superior Twin là sự lựa chọn lý tưởng dành cho các gia đình nhỏ, nhóm bạn hoặc đồng nghiệp đi công tác đang tìm kiếm một không gian lưu trú thoải mái, tiện nghi và tiết kiệm chi phí. Với thiết kế thông minh, tối ưu hóa diện tích, hạng phòng này mang lại không gian sinh hoạt chung ấm cúng nhưng vẫn đảm bảo sự riêng tư cho mỗi cá nhân.\r\n\r\nCác đặc điểm và tiện nghi nổi bật:\r\n\r\n★ Bố trí giường linh hoạt: Phòng được trang bị 2 giường đơn cỡ lớn (hoặc 1 giường đôi và 1 giường đơn tùy phòng), sử dụng bộ chăn ga gối đệm sắc trắng tinh khôi, êm ái, mang lại giấc ngủ trọn vẹn sau ngày dài di chuyển.\r\n\r\n★ Không gian nội thất ấm cúng: Thiết kế hài hòa với sàn gỗ hoặc sàn gạch vân đá cao cấp. Toàn bộ nội thất như tủ quần áo, tab đầu giường, bàn trang điểm đều được làm từ gỗ tự nhiên với tông màu ấm áp.\r\n\r\n★ Khu vực thư giãn tiện lợi: Một góc nhỏ trong phòng được bố trí bộ bàn trà/cà phê với ghế nệm sofa đơn sắc màu nổi bật (như cam hoặc vàng), kết hợp với cây xanh trang trí mang lại cảm giác tươi mới, dễ chịu.\r\n\r\n★ Trang thiết bị hiện đại:\r\n\r\n     ⚝ Hệ thống điều hòa không khí âm trần thế hệ mới.\r\n\r\n     ⚝ Tủ gỗ đa năng tích hợp tủ lạnh mini (minibar), bình đun nước siêu tốc, máy sấy tóc và nước suối miễn phí mỗi ngày.\r\n\r\n★ Phòng tắm hiện đại &amp; Sang trọng: Không gian phòng tắm rộng rãi, sạch sẽ với hai phong cách thiết kế ấn tượng: tích hợp bồn tắm nằm thư giãn hoặc phòng tắm kính đứng hiện đại, kết hợp gạch ốp tường nghệ thuật và đầy đủ đồ dùng cá nhân cao cấp.', 0, 2),
(9, 9, 'lyly_room_cat', 'VIP Room là hạng phòng cao cấp nhất, mang đến không gian nghỉ dưỡng thượng lưu, rộng rãi và biệt lập. Được thiết kế chú trọng vào sự sang trọng và tiện nghi vượt trội, đây là lựa chọn hoàn hảo cho những chuyến công tác, kỳ nghỉ trăng mật hoặc những khách hàng muốn tự thưởng cho mình một trải nghiệm lưu trú đẳng cấp nhất.\r\n\r\nNhững đặc quyền và điểm nhấn nổi bật:\r\n\r\n★ Không gian đẳng cấp &amp; Tầm nhìn panorama: Phòng sở hữu diện tích lớn với hệ thống cửa vòm kính kéo dài từ trần xuống sàn, mở ra một ban công rộng rãi. Tại đây được trang bị sẵn bộ bàn ghế ngoài trời để bạn có thể thư thái nhâm nhi cà phê và ngắm nhìn toàn cảnh thành phố thơ mộng.\r\n\r\n★ Nội thất thượng hạng: Sàn đá marble vân mây sang trọng kết hợp hài hòa với nội thất gỗ tự nhiên cao cấp. Giường ngủ King-size được bố trí ở trung tâm phòng với bộ chăn ga gối đệm êm ái, mang lại giấc ngủ hoàng gia.\r\n\r\n★ Khu vực tiếp khách riêng biệt: Ngay trong phòng được bố trí một băng ghế sofa da dáng cong hiện đại màu cam ấm cùng bàn trà tinh tế, tạo không gian lịch sự để tiếp khách hoặc thư giãn xem TV.\r\n\r\n★ Tiện nghi VIP đầy đủ: * Hệ thống điều hòa âm trần hiện đại.\r\n\r\n     ⚝ Smart TV màn hình lớn, tủ lạnh mini tích hợp gọn gàng trong tủ gỗ.\r\n\r\n     ⚝ Bàn trang điểm/bàn làm việc riêng, tủ quần áo lớn, bình đun nước siêu tốc và bộ tách trà sứ cao cấp.\r\n\r\n★ Nghệ thuật bài trí: Căn phòng thêm phần sinh động và thư thái nhờ các bức tranh phong cảnh thiên nhiên rực rỡ cùng các chậu cây xanh phong thủy thanh lọc không khí như cây Lưỡi Hổ.', 0, 2),
(10, 10, 'lyly_room_cat', 'Standard Room là sự lựa chọn tối ưu và tiết kiệm nhất dành cho khách du lịch một mình hoặc các cặp đôi mong muốn một không gian lưu trú ấm cúng, sạch sẽ và đầy đủ tiện nghi cơ bản. Với phong cách thiết kế chú trọng vào sự gọn gàng và công năng, hạng phòng Standard mang lại cảm giác gần gũi, thoải mái như đang ở chính ngôi nhà của mình.\r\n\r\nNhững điểm nổi bật của hạng phòng:\r\n\r\n★ Không gian ấm cúng &amp; Riêng tư: Phòng được thiết kế thông minh với tường ốp gỗ xen lẫn mảng đá marble tạo điểm nhấn sang trọng, sạch sẽ. Hệ thống trần thạch cao giật cấp kết hợp ánh sáng đèn LED dịu nhẹ tạo nên không gian nghỉ ngơi vô cùng thư thái.\r\n\r\n★ Giường ngủ tiêu chuẩn êm ái: Trang bị 1 giường đôi cỡ lớn với nệm lò xo cao cấp, gối ôm và bộ chăn ga trắng tinh khôi được thay mới hàng ngày, mang đến cho bạn một giấc ngủ ngon và trọn vẹn.\r\n\r\n★ Góc tiện ích xinh xắn: Một bộ bàn ghế gỗ nhỏ hoặc ghế nệm sofa da được bố trí cạnh cửa sổ, đi kèm bộ tách trà sứ để bạn thưởng thức đồ uống mỗi sáng.\r\n\r\n     ⚝ Bàn trang điểm/bàn làm việc nhỏ gọn kết hợp gương treo tường viền thừng độc đáo.\r\n\r\n★ Trang thiết bị đầy đủ: Phòng được trang bị sẵn điều hòa nhiệt độ, TV màn hình phẳng treo tường tiết kiệm không gian, tủ gỗ, máy sấy tóc và các vật dụng cá nhân cần thiết.\r\n\r\n★ Phòng tắm đứng hiện đại: Không gian phòng tắm được ốp gạch mosaic tông màu trung tính sạch sẽ, sử dụng vách kính đứng ngăn vùng khô - ướt hiện đại, đi kèm vòi sen tăng áp mang lại cảm giác sảng khoái khi sử dụng.', 0, 1),
(11, 11, 'lyly_room_cat', 'Double Deluxe mang đến một không gian nghỉ dưỡng đẳng cấp, rộng rãi bậc nhất, được thiết kế đặc biệt để đáp ứng nhu cầu lưu trú tự do, thoải mái của các gia đình hoặc nhóm bạn thân. Sở hữu diện tích lớn cùng sự kết hợp tinh tế giữa nội thất gỗ cổ điển và những tiện nghi hiện đại, hạng phòng này cam kết đem lại trải nghiệm thư thái tuyệt đối cho chuyến đi của bạn.\r\n\r\nNhững điểm ấn tượng độc đáo:\r\n\r\n★ Không gian nghỉ ngơi linh hoạt &amp; Rộng rãi: Phòng được bố trí 2 giường đôi cỡ lớn song song với đệm lò xo êm ái, gối tựa thêu logo tinh xảo và bộ chăn ga trắng muốt. Thiết kế này tạo điều kiện cho các thành viên dễ dàng sinh hoạt chung mà vẫn sở hữu góc nghỉ ngơi rộng rãi, biệt lập.\r\n\r\n★ Thiết kế sang trọng, ngập tràn ánh sáng: Điểm đắt giá của căn phòng là hệ thống cửa kính lớn chạm trần chạy dọc phòng, mở ra tầm nhìn thoáng đãng và đón trọn ánh sáng tự nhiên. Mảng tường đầu giường được ốp đá hoa cương vân loang kết hợp cùng gỗ cao cấp, tạo nên một tổng thể vô cùng quý phái.\r\n\r\n★ Góc sinh hoạt chung ấm cúng: Một bộ bàn ghế gỗ đồng kị truyền thống được đặt cạnh cửa sổ kính, kết hợp bình trà gốm sứ cao cấp, là nơi lý tưởng để cả nhà cùng ngồi trò chuyện, thưởng trà và ngắm cảnh.\r\n\r\n★ Trang thiết bị cao cấp đầy đủ:\r\n\r\n     ⚝ Hệ thống đèn trần thạch cao phối đèn chùm nghệ thuật tỏa ánh sáng ấm áp.\r\n\r\n     ⚝ Trang bị sẵn điều hòa nhiệt độ, TV màn hình lớn, tủ kệ gỗ đầu giường tiện lợi, điện thoại bàn và tủ quần áo lớn.\r\n\r\n★ Phòng tắm tiện nghi với bồn tắm nằm: Không gian phòng tắm rộng rãi, sạch sẽ với tường ốp gạch men họa tiết hoa thanh lịch. Khách lưu trú có thể thư giãn tối đa trong bồn tắm nằm dài, sử dụng hệ thống vòi sen cây mát lạnh giúp rũ bỏ mọi mệt mỏi sau ngày dài khám phá.', 0, 1),
(12, 12, 'lyly_room_cat', 'Twin Room (Phòng hai giường) là giải pháp lưu trú hoàn hảo dành cho các gia đình, nhóm bạn hoặc đồng nghiệp đi công tác cùng nhau. Sở hữu diện tích rộng rãi cùng lối thiết kế thông minh, hạng phòng này mang lại sự cân bằng tuyệt vời giữa không gian kết nối chung ấm cúng và sự riêng tư tuyệt đối cho từng cá nhân.\r\n\r\nNhững điểm nhấn nổi bật của hạng phòng:\r\n\r\n★ Không gian nghỉ ngơi rộng rãi, linh hoạt: Phòng được bố trí 2 giường đôi cỡ lớn song song giúp tối ưu hóa diện tích sử dụng. Toàn bộ giường đều trang bị đệm lò xo cao cấp, gối ôm thêu họa tiết sang trọng và chăn ga trắng tinh khôi, mang lại giấc ngủ sâu và êm ái cho mỗi khách lưu trú.\r\n\r\n★ Thiết kế sang trọng &amp; Ngập tràn ánh sáng: Căn phòng khoác lên mình vẻ đẹp quý phái với mảng tường đá hoa cương cao cấp kết hợp gỗ ốp đầu giường sang trọng. Hệ thống cửa kính lớn sát trần đi kèm rèm hai lớp giúp căn phòng luôn tràn ngập ánh sáng tự nhiên và mở ra tầm nhìn thoáng đãng.\r\n\r\nGóc thư giãn đậm chất truyền thống: Ngay cạnh khung cửa kính lớn được bố trí bộ bàn ghế gỗ đồng kị cổ điển cùng bộ ấm trà gốm sứ tinh tế, tạo nên góc lý tưởng để các thành viên cùng ngồi nhâm nhi trà, trò chuyện và ngắm cảnh.\r\n\r\n★ Trang thiết bị hiện đại: Phòng được tích hợp đầy đủ các tiện ích cao cấp như đèn chùm nghệ thuật tỏa ánh sáng ấm áp, điều hòa không khí, TV màn hình lớn, điện thoại bàn và tủ kệ gỗ tiện lợi.\r\n\r\n★ Phòng tắm đứng hiện đại, sạch sẽ: Không gian phòng tắm được ốp gạch mosaic tông màu trầm ấm, trang bị vách kính đứng hiện đại ngăn vùng khô - ướt, cùng vòi sen tăng áp giúp bạn rũ bỏ mọi mệt mỏi sau một ngày dài di chuyển.', 0, 1);
