(48, 'Trải nghiệm LyLy Hotel với các gói kỳ nghỉ độc quyền của chúng tôi, những trải nghiệm đặc sắc và ưu đãi đặc biệt.', 'Experience LyLy Hotel with our exclusive holiday packages, unique experiences, and special offers.', 1, 0, 48),
(49, 'XEM THÊM', 'SEE MORE', 1, 0, 49),
(50, 'ĐẾN VÀ TRẢI NGHIỆM', 'COME AND EXPERIENCE IT', 1, 0, 50),
(51, 'THỊ GIÁC', 'VISION', 1, 0, 51),
(52, 'Lấy cảm hứng từ kiến trúc Châu Âu sang trọng để thấy được vẻ đẹp từ nhiều thứ, đặc biệt là những công trình kiến trúc tinh tế do bàn tay con người tạo ra.', 'Inspired by elegant European architecture, we can appreciate the beauty in many things, especially the exquisite architectural works created by human hands.', 1, 0, 52),
(53, 'VỊ GIÁC', 'TASTE', 1, 0, 53),
(54, 'Thưởng thức sự bùng nổ trong hương vị của từng món ăn, thức uống được chế biến để thưởng thức hương vị tuyệt vời của các món ăn và đồ uống từ các đầu bếp chuyên nghiệp tại khách sạn.', 'Enjoy the explosion of flavor in each dish and drink, expertly prepared by professional chefs at the hotel.', 1, 0, 54),
(55, 'KHƯỚU GIÁC', 'SENSE OF LOUIS', 1, 0, 55),
(56, 'Đánh thức mọi giác quan bằng mùi hương tinh tế của tinh dầu thiên nhiên, xua tan mọi mệt mỏi sau một ngày dài khám phá.', 'Awaken all your senses with the delicate aroma of natural essential oils, dispelling all fatigue after a long day of exploration.', 1, 0, 56),
(57, 'THÍNH GIÁC', 'HEARING', 1, 0, 57),
(58, 'Lắng nghe thanh âm êm dịu của tiếng sóng biển hòa quyện cùng bản nhạc du dương, tạo nên một không gian thư giãn hoàn hảo.', 'Listen to the soothing sound of the waves blending with the gentle music, creating a perfect relaxing atmosphere.', 1, 0, 58),
(59, 'XÚC GIÁC', 'TACTILE', 1, 0, 59),
(60, 'Cảm nhận sự mềm mại từ những bộ chăn ga gối đệm cao cấp và sự chăm sóc tận tình tại dịch vụ Spa đẳng cấp của chúng tôi.', 'Experience the softness of our premium bedding and the attentive care at our world-class spa service.', 1, 0, 60),
(61, 'HƠN THẾ NỮA', 'MORE THAN THAT', 1, 0, 61),
(62, 'Hãy kết nối với chúng tôi để luôn được cập nhật thông tin và chương trình ưu đãi mới nhất.', 'Stay connected with us to keep you updated on the latest information and promotions.', 1, 0, 62),
(63, 'ĐĂNG KÝ', 'REGISTER', 1, 0, 63),
