(220, 'Khách Sạn Ly Ly - Điểm Đến Cho Ngày Trọng Đại', 'Ly Ly Hotel - The Destination for Your Big Day', 1, 0, 220),
(221, 'Cho dù bạn đang lên kế hoạch cho một buổi tiệc thân mật hay một lễ kỷ niệm lớn, đội ngũ chuyên nghiệp của chúng tôi sẽ giúp bạn thiết kế ngày trọng đại tại các địa điểm tổ chức tiệc cưới của Ly Ly.', 'Whether you&#039;re planning an intimate party or a grand celebration, our professional team will help you design your big day at Ly Ly&#039;s wedding venues.', 1, 0, 221),
(222, 'Các gói tiệc cưới tại Vũng Tàu đáp ứng mọi nhu cầu, bao gồm chụp ảnh, hoa tươi và nhiều hơn nữa. Các địa điểm tiệc cưới đa dạng và linh hoạt, có thể phục vụ tiệc từ 50 đến 250 khách.', 'Wedding packages in Vung Tau cater to all needs, including photography, fresh flowers, and more. The venues are diverse and flexible, accommodating from 50 to 250 guests.', 1, 0, 222),
(223, 'Làm việc với đội ngũ phục vụ chuyên nghiệp sẽ cho phép bạn tạo ra thực đơn thể hiện tinh hoa của ngày đặc biệt.', 'Working with a professional service team will allow you to create a menu that reflects the essence of the special day.', 1, 0, 223),
(224, 'WEDDING FAQS', 'WEDDING FAQS', 1, 0, 224),
(225, 'GỬI YÊU CẦU', 'SUBMIT REQUEST', 1, 0, 225),
(226, 'Special Day', 'Special Day', 1, 0, 226),
(227, 'WELCOME TO LYLY HOTEL', 'WELCOME TO LYLY HOTEL', 1, 0, 227),
(228, 'Sáng tạo - Sang trọng - Đẳng cấp.', 'Creative - Elegant - Classy.', 1, 0, 228),
(229, 'MEETINGS & EVENTS', 'Meetings &amp; Events', 1, 0, 229),
(230, 'CREATE MEMORABLE', 'CREATE MEMORABLE', 1, 0, 230),
(231, 'Khách sạn LyLy cung cấp không gian hội nghị linh hoạt với sức chứa lên đến 450 khách. \n            Các phòng hội nghị lớn có thể chia nhỏ thành 3 phòng riêng biệt với hệ thống vách ngăn hiện đại.\n            Hệ thống âm thanh ánh sáng đạt chuẩn quốc tế, màn hình LED hiện đại sẵn sàng đáp ứng mọi nhu cầu của quý khách.', 'LyLy Hotel offers flexible conference spaces with a capacity of up to 450 guests. Large conference rooms can be divided into three separate rooms using modern partition systems. International standard sound and lighting systems, along with modern LED screens, are ready to meet all your needs.', 1, 0, 231),
(232, 'Xem chi tiết', 'See details', 1, 0, 232),
(233, 'Hội thảo', 'Seminar', 1, 0, 233),
(234, 'Không gian chuyên nghiệp cho các buổi thảo luận và đào tạo.', 'A professional space for discussions and training sessions.', 1, 0, 234),
(235, 'Hơn 20,000 feet vuông không gian linh hoạt', 'Over 20,000 square feet of flexible space', 1, 0, 235),
(236, 'Công nghệ nghe nhìn tiên tiến', 'Advanced audiovisual technology', 1, 0, 236),
(237, 'Thực đơn tiệc tự chọn linh hoạt', 'Flexible buffet menu', 1, 0, 237),
(238, 'Địa điểm lý tưởng cho các hội nghị quy mô lớn và quan trọng.', 'An ideal location for large-scale and important conferences.', 1, 0, 238),
(239, 'Phòng họp đa chức năng', 'Multi-functional meeting room', 1, 0, 239),
(240, 'Đội ngũ hỗ trợ kỹ thuật tận tâm', 'Dedicated technical support team', 1, 0, 240),
(241, 'Dịch vụ ẩm thực cao cấp', 'High-end culinary services', 1, 0, 241),
(242, 'Sự kiện', 'Event', 1, 0, 242),
(243, 'Tổ chức những sự kiện đáng nhớ và rực rỡ nhất.', 'Organize the most memorable and spectacular events.', 1, 0, 243),
(244, 'Không gian tiệc ngoài trời và trong nhà', 'Outdoor and indoor party spaces', 1, 0, 244),
(245, 'Trang trí theo yêu cầu', 'Custom decoration', 1, 0, 245),
(246, 'Hệ thống đèn LED công suất lớn', 'High-power LED lighting system', 1, 0, 246),
(247, 'Dine', 'Dine', 1, 0, 247),
