(27, 'CHÀO MỪNG ĐẾN VỚI LYLY HOTEL'),
(28, 'Chào mừng bạn đến với'),
(29, 'LyLy Hotel'),
(30, '– điểm đến lý tưởng tọa lạc ngay trung tâm thành phố biển xinh đẹp. Với kiến trúc hiện đại, dịch vụ đạt tiêu chuẩn quốc tế và không gian sang trọng, LyLy Hotel là lựa chọn hoàn hảo cho cả kỳ nghỉ dưỡng lẫn chuyến công tác.'),
(31, 'Chúng tôi tự hào mang đến cho bạn một kỳ nghỉ tuyệt vời với nhiều hạng phòng đa dạng, hồ bơi ngoài trời thư giãn, nhà hàng cao cấp phục vụ ẩm thực Á – Âu tinh tế cùng hệ thống phòng họp trang bị đầy đủ tiện nghi.'),
(32, '– Nơi khởi đầu cho những trải nghiệm khó quên.'),
(33, 'CHỈ CÓ TẠI LYLY HOTEL'),
(34, 'M GYM'),
(35, 'LEARN MORE'),
(36, 'M SPA'),
(37, 'BILLIARD & FOOSBALL'),
(38, 'ENTERTAINMENT'),
(39, 'M POOL'),
(40, 'CARINA RESTAURANT'),
(41, 'VELA RESTAURANT'),
(42, 'THE LUX COFFEE'),
(43, 'GIFT SHOP'),
(44, 'KID ZONE'),
(45, 'CONFERENCE'),
(46, 'PRIVATE LAUNDRY'),
(47, 'GÓI ƯU ĐÃI'),
(48, 'Trải nghiệm LyLy Hotel với các gói kỳ nghỉ độc quyền của chúng tôi, những trải nghiệm đặc sắc và ưu đãi đặc biệt.'),
(49, 'XEM THÊM'),
(50, 'ĐẾN VÀ TRẢI NGHIỆM'),
(51, 'THỊ GIÁC'),
(52, 'Lấy cảm hứng từ kiến trúc Châu Âu sang trọng để thấy được vẻ đẹp từ nhiều thứ, đặc biệt là những công trình kiến trúc tinh tế do bàn tay con người tạo ra.'),
(53, 'VỊ GIÁC'),
(54, 'Thưởng thức sự bùng nổ trong hương vị của từng món ăn, thức uống được chế biến để thưởng thức hương vị tuyệt vời của các món ăn và đồ uống từ các đầu bếp chuyên nghiệp tại khách sạn.'),
(55, 'KHƯỚU GIÁC'),
(56, 'Đánh thức mọi giác quan bằng mùi hương tinh tế của tinh dầu thiên nhiên, xua tan mọi mệt mỏi sau một ngày dài khám phá.'),
(57, 'THÍNH GIÁC'),
(58, 'Lắng nghe thanh âm êm dịu của tiếng sóng biển hòa quyện cùng bản nhạc du dương, tạo nên một không gian thư giãn hoàn hảo.'),
(59, 'XÚC GIÁC'),
(60, 'Cảm nhận sự mềm mại từ những bộ chăn ga gối đệm cao cấp và sự chăm sóc tận tình tại dịch vụ Spa đẳng cấp của chúng tôi.'),
(61, 'HƠN THẾ NỮA'),
(62, 'Hãy kết nối với chúng tôi để luôn được cập nhật thông tin và chương trình ưu đãi mới nhất.'),
(63, 'ĐĂNG KÝ'),
(64, 'Tôi đồng ý với chính sách bảo mật và các điều khoản và điều kiện'),
